// Validate the shared runtime configuration before other workflows consume it.
const config = $input.first().json;
const errors = [];

if (config.timezone !== 'Asia/Taipei') errors.push('timezone must be Asia/Taipei');
if (!Number.isInteger(config.dailyLimit) || config.dailyLimit < 1) errors.push('dailyLimit must be a positive integer');
if (!Number.isInteger(config.ragTopK) || config.ragTopK < 1) errors.push('ragTopK must be a positive integer');
if (!config.primaryBaseUrl.startsWith('https://')) errors.push('primaryBaseUrl must use HTTPS');
if (!config.fallbackBaseUrl.startsWith('https://')) errors.push('fallbackBaseUrl must use HTTPS');
if (!config.primaryModel) errors.push('primaryModel is required');

if (errors.length) {
  throw new Error(`Invalid Phoenix runtime configuration: ${errors.join('; ')}`);
}

return [{
  json: {
    ...config,
    status: 'ready',
    credentialsRequired: [
      'OpenRouter API',
      'NVIDIA NIM API',
      'Qdrant Cloud API'
    ],
    fallbackModelConfigured: Boolean(config.fallbackModel)
  }
}];
